const input = JSON.parse(query);
const severity = input.severity || 'L2';
const category = (input.category || '').toLowerCase();
const region = (input.region || '').toLowerCase();

let sla_hours = 24;
let priority = 'Medium';
let escalation_timeline = '';
let response_time = '';

if (severity === 'L1') {
  sla_hours = 8;
  priority = 'Standard';
  response_time = '2 hours';
  escalation_timeline = 'Auto-close if no response in 48 hours';
} else if (severity === 'L2') {
  sla_hours = 24;
  priority = 'High';
  response_time = '1 hour';
  escalation_timeline = 'Escalate to senior tech after 12 hours, manager after 24 hours';
} else if (severity === 'L3') {
  sla_hours = 4;
  priority = 'Critical';
  response_time = '15 minutes';
  escalation_timeline = 'Immediate engineering escalation, management notified within 1 hour, executive briefing if unresolved in 4 hours';
}

// Adjust for safety-critical categories
if (category.includes('gas leak') || category.includes('safety')) {
  sla_hours = 1;
  priority = 'Emergency';
  response_time = 'Immediate';
  escalation_timeline = 'Emergency response team dispatched immediately. Regulatory notification within 30 minutes.';
}

return JSON.stringify({
  sla_hours: sla_hours,
  priority: priority,
  response_time: response_time,
  escalation_timeline: escalation_timeline,
  target_resolution: sla_hours + ' hours',
  region: region
});

const input = JSON.parse(query);
const category = (input.category || '').toLowerCase();
const asset_type = (input.asset_type || '').toLowerCase();
const description = (input.description || '').toLowerCase();

let severity = 'L2';
let reason = '';

// L3 - Critical
if (description.includes('gas leak') || description.includes('safety') || 
    description.includes('explosion') || description.includes('regulatory') ||
    description.includes('firmware bug') || description.includes('cybersecurity') ||
    category.includes('gas leak') || category.includes('safety') ||
    category.includes('cybersecurity') || category.includes('pipeline integrity')) {
  severity = 'L3';
  reason = 'Safety-critical or engineering-level issue requiring immediate escalation';
}
// L1 - Simple
else if (description.includes('billing') || description.includes('configuration') ||
         description.includes('reset') || description.includes('reboot') ||
         description.includes('password') || category.includes('billing') ||
         category.includes('meter configuration')) {
  severity = 'L1';
  reason = 'Known issue with documented resolution, standard operational fix';
}
// L2 - Default
else {
  severity = 'L2';
  reason = 'Requires technical investigation, logs review, or configuration analysis';
}

return JSON.stringify({
  severity: severity,
  reason: reason,
  category: category,
  asset_type: asset_type
});

const input = JSON.parse(query);
const severity = input.severity || 'L2';
const category = (input.category || '').toLowerCase();
const asset_type = (input.asset_type || '').toLowerCase();
const region = (input.region || '').toLowerCase();

let team = 'Field Operations';
let escalation_path = [];
let routing_notes = '';

// Route based on category
if (category.includes('firmware') || category.includes('scada')) {
  team = 'Engineering';
  escalation_path = ['L1: Engineering Support', 'L2: Senior Engineer', 'L3: Engineering Director'];
  routing_notes = 'Requires engineering analysis and potential code fix';
} else if (category.includes('billing') || category.includes('meter configuration')) {
  team = 'Billing & Metering';
  escalation_path = ['L1: Billing Support', 'L2: Billing Supervisor', 'L3: Revenue Assurance Manager'];
  routing_notes = 'Standard billing/metering issue, check configuration first';
} else if (category.includes('cybersecurity') || category.includes('it infrastructure')) {
  team = 'IT Security';
  escalation_path = ['L1: IT Help Desk', 'L2: Security Analyst', 'L3: CISO'];
  routing_notes = 'Security protocol required, isolate affected systems';
} else if (category.includes('gas leak') || category.includes('safety') || category.includes('pipeline')) {
  team = 'Safety & Emergency Response';
  escalation_path = ['Immediate: Emergency Response Team', 'Concurrent: Safety Director', 'Regulatory: Compliance Officer'];
  routing_notes = 'EMERGENCY: Follow safety protocol SOP-001. Notify regulatory if required.';
} else if (category.includes('grid') || category.includes('transformer')) {
  team = 'Grid Operations';
  escalation_path = ['L1: Grid Operator', 'L2: Grid Engineer', 'L3: Grid Operations Director'];
  routing_notes = 'Monitor grid stability, check SCADA readings';
} else {
  team = 'Field Operations';
  escalation_path = ['L1: Field Technician', 'L2: Field Supervisor', 'L3: Operations Manager'];
  routing_notes = 'Dispatch field team for on-site investigation';
}

return JSON.stringify({
  recommended_team: team,
  escalation_path: escalation_path,
  routing_notes: routing_notes,
  region_dispatch: region,
  severity_level: severity
});

const input = JSON.parse(query);
const category = (input.category || '').toLowerCase();
const description = (input.description || '').toLowerCase();
const asset_type = (input.asset_type || '').toLowerCase();
const severity = input.severity || 'L2';

let compliance_flags = [];
let regulatory_actions = [];
let requires_notification = false;
let regulatory_body = '';

if (category.includes('gas leak') || description.includes('gas leak')) {
  compliance_flags.push('PHMSA Pipeline Safety Regulation');
  regulatory_actions.push('File incident report within 24 hours');
  regulatory_actions.push('Notify state pipeline safety office');
  requires_notification = true;
  regulatory_body = 'PHMSA (Pipeline and Hazardous Materials Safety Administration)';
}

if (category.includes('safety') || description.includes('explosion') || description.includes('injury')) {
  compliance_flags.push('OSHA Workplace Safety');
  regulatory_actions.push('Complete OSHA Form 301 if injury involved');
  requires_notification = true;
  regulatory_body = regulatory_body ? regulatory_body + ', OSHA' : 'OSHA';
}

if (description.includes('cybersecurity') || category.includes('cybersecurity')) {
  compliance_flags.push('NERC CIP Cybersecurity Standards');
  regulatory_actions.push('Report to NERC ES-ISAC within 1 hour');
  regulatory_actions.push('Initiate incident response plan IRP-001');
  requires_notification = true;
  regulatory_body = regulatory_body ? regulatory_body + ', NERC' : 'NERC';
}

if (category.includes('billing') || description.includes('overcharg')) {
  compliance_flags.push('PUC Consumer Protection Rules');
  regulatory_actions.push('Document billing discrepancy for PUC audit trail');
  regulatory_body = regulatory_body ? regulatory_body + ', PUC' : 'PUC (Public Utility Commission)';
}

if (asset_type.includes('meter') && (description.includes('accuracy') || description.includes('wrong reading'))) {
  compliance_flags.push('ANSI C12 Metering Standards');
  regulatory_actions.push('Schedule meter accuracy test per ANSI C12.20');
}

if (compliance_flags.length === 0) {
  compliance_flags.push('No immediate regulatory concerns');
  regulatory_actions.push('Standard operational procedures apply');
}

return JSON.stringify({
  compliance_flags: compliance_flags,
  regulatory_actions: regulatory_actions,
  requires_regulatory_notification: requires_notification,
  regulatory_body: regulatory_body || 'None',
  compliance_status: requires_notification ? 'ACTION REQUIRED' : 'COMPLIANT',
  review_deadline: requires_notification ? '24 hours' : 'Standard review cycle'
});
